import { z } from 'zod';
import dotenv from 'dotenv';

// 環境変数を読み込む
dotenv.config();

// 环境变数検証スキーマ
const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
  PORT: z.string().transform(Number).default(3000),

  // 統一された LLM 設定
  LLM_MODEL_PROVIDER: z.string().default('openai'),
  LLM_MODEL_NAME: z.string().default('gpt-4o-mini'),
  LLM_BASE_URL: z.string().default('https://api.openai.com/v1'),
  LLM_MAX_TOKENS: z.string().transform(Number).default(8192),
  LLM_TEMPERATURE: z.string().transform(Number).default(0.7),
  LLM_API_KEY: z.string().min(1, 'LLM_API_KEY is required and cannot be empty'),

  // 允许使用的模型列表（逗号分隔），留空表示允许所有模型
  ALLOW_MODELS: z.string().optional(),

  // 允许使用的MCP工具列表（逗号或分号分隔），留空表示允许所有工具
  ALLOWED_MCP_TOOLS: z.string().optional(),

  LOG_LEVEL: z.enum(['error', 'warn', 'info', 'debug']).default('info'),

  // LINE Bot 配置
  LINE_CHANNEL_SECRET: z.string().optional(),
  LINE_ACCESS_TOKEN: z.string().optional(),

  // 搜索 API 配置
  TAVILY_API_KEY: z.string().optional(),
  JINA_API_KEY: z.string().optional(),

  // データベース配置
  DATABASE_URL: z.string().url(),
  DB_TYPE: z.string().default('postgresql'),

  // JWT & 認証配置
  JWT_SECRET: z.string().min(16, 'JWT_SECRET must be at least 16 characters'),
  JWT_EXPIRES_IN: z.coerce.number().default(86400), // 24 hours
  SESSION_TOKEN_EXPIRES_IN: z.coerce.number().default(604800), // 7 days

  // デフォルト管理者アカウント
  DEFAULT_ADMIN_EMAIL: z.string().email().default('admin@example.com'),
  DEFAULT_ADMIN_PASSWORD: z.string().min(8).default('Admin123!@#'),
});

// 検証および設定のエクスポート
const env = envSchema.parse(process.env);

// デバッグログ：環境変数の確認
console.log('=== 環境変数デバッグ ===');
console.log('LLM_MODEL_PROVIDER:', process.env.LLM_MODEL_PROVIDER);
// Mask LLM_BASE_URL - show only last 4 characters
const maskedBaseUrl = process.env.LLM_BASE_URL 
  ? '********' + process.env.LLM_BASE_URL.slice(-4)
  : '未設定';
console.log('LLM_BASE_URL:', maskedBaseUrl);
// Mask LLM_API_KEY - show only last 4 characters
const maskedApiKey = process.env.LLM_API_KEY 
  ? '********' + process.env.LLM_API_KEY.slice(-4)
  : '未設定';
console.log('LLM_API_KEY:', maskedApiKey);
console.log('=====================');

export const config = {
  app: {
    env: env.NODE_ENV,
    port: env.PORT,
    logLevel: env.LOG_LEVEL,
  },
  llm: {
    apiKey: env.LLM_API_KEY || '',
    baseUrl: env.LLM_BASE_URL,
    modelProvider: env.LLM_MODEL_PROVIDER,
    modelName: env.LLM_MODEL_NAME,
    maxTokens: env.LLM_MAX_TOKENS,
    temperature: env.LLM_TEMPERATURE,
    allowedModels: env.ALLOW_MODELS ? env.ALLOW_MODELS.split(/[,;]/).map(m => m.trim()).filter(m => m.length > 0) : undefined,
  },
  mcp: {
    allowedTools: env.ALLOWED_MCP_TOOLS ? env.ALLOWED_MCP_TOOLS.split(/[,;]/).map(t => t.trim()).filter(t => t.length > 0) : undefined,
  },
  line: {
    channelSecret: env.LINE_CHANNEL_SECRET,
    accessToken: env.LINE_ACCESS_TOKEN,
  },
  search: {
    tavilyApiKey: env.TAVILY_API_KEY,
    jinaApiKey: env.JINA_API_KEY,
  },
  database: {
    url: env.DATABASE_URL,
    type: env.DB_TYPE,
  },
  auth: {
    jwtSecret: env.JWT_SECRET,
    jwtExpiresIn: env.JWT_EXPIRES_IN,
    sessionTokenExpiresIn: env.SESSION_TOKEN_EXPIRES_IN,
    defaultAdminEmail: env.DEFAULT_ADMIN_EMAIL,
    defaultAdminPassword: env.DEFAULT_ADMIN_PASSWORD,
  },
};

export type Config = typeof config;

import { config } from '../config/environment.js';
import { Logger } from '../utils/logger.js';

// モデル設定インターフェース
export interface ModelConfig {
  name: string;
  displayName: string;
  provider: string;
  baseUrl: string;
  apiKey?: string;
  maxTokens: number;
  temperature: number;
  description?: string;
  isEnabled: boolean;
}

// 模型健康检查结果
export interface ModelHealthStatus {
  name: string;
  isHealthy: boolean;
  responseTime?: number;
  lastChecked: Date;
  error?: string;
}

export class ModelManager {
  private static instance: ModelManager;
  private models: Map<string, ModelConfig> = new Map();
  private healthStatus: Map<string, ModelHealthStatus> = new Map();
  private isInitialized = false;
  private initializationPromise: Promise<void> | null = null;

  private constructor() {
    // 延迟初始化，通过 async initialize() 方法
  }

  public static getInstance(): ModelManager {
    if (!ModelManager.instance) {
      ModelManager.instance = new ModelManager();
    }
    return ModelManager.instance;
  }

  /**
   * 非同期でモデル設定を初期化
   * LLM サーバーから /v1/models エンドポイントを照会して、動的にモデル設定を構築
   */
  public async initialize(): Promise<void> {
    if (this.isInitialized) {
      return;
    }

    if (this.initializationPromise) {
      return this.initializationPromise;
    }

    this.initializationPromise = this.initializeModelsFromServer();
    await this.initializationPromise;
    this.isInitialized = true;
  }

  /**
   * LLM サーバーからモデルリストを取得して設定を初期化
   */
  private async initializeModelsFromServer(): Promise<void> {
    Logger.info('LLM サーバーからモデル設定を初期化中...');

    try {
      // Mask the URL for logging
      const maskedUrl = config.llm.baseUrl 
        ? '********' + config.llm.baseUrl.slice(-4)
        : '未設定';
      Logger.info('LLM API にモデルリストを照会', { url: maskedUrl });

      // LLM API からモデルリストを取得
      const response = await fetch(`${config.llm.baseUrl}/models`, {
        method: 'GET',
        headers: {
          'Content-Type': 'application/json',
          ...(config.llm.apiKey ? { 'Authorization': `Bearer ${config.llm.apiKey}` } : {})
        }
      });

      if (!response.ok) {
        throw new Error(`LLM API からのモデル取得に失敗しました：${response.status} ${response.statusText}`);
      }

      const llmResponse = await response.json();
      const llmModels = llmResponse.data || [];

      if (!Array.isArray(llmModels) || llmModels.length === 0) {
        Logger.warn('LLM API からモデルが返されませんでした。フォールバックします');
        this.initializeFallbackModels();
        return;
      }

      // 各モデルの設定を構築
      for (const model of llmModels) {
        const modelConfig: ModelConfig = {
          name: model.id,
          displayName: model.id,
          provider: config.llm.modelProvider as 'openai' | 'anthropic',
          baseUrl: config.llm.baseUrl,
          apiKey: config.llm.apiKey || undefined,
          maxTokens: config.llm.maxTokens,
          temperature: config.llm.temperature,
          description: `由 ${model.owned_by || config.llm.modelProvider} 提供`,
          isEnabled: true
        };

        this.models.set(modelConfig.name, modelConfig);
      }

      Logger.info(`${this.models.size} 個のモデル設定を LLM サーバーから読み込みました`);

    } catch (error) {
      Logger.error('LLM サーバーからのモデル初期化に失敗しました。フォールバックします', { 
        error: (error as Error).message 
      });
      this.initializeFallbackModels();
    }
  }

  /**
   * フォールバック用のモデル設定を初期化（LLM API 利用不可の場合）
   */
  private initializeFallbackModels(): void {
    Logger.info('フォールバックモデル設定を初期化中...');

    // 主要モデル配置（来自环境变量）
    const primaryModel: ModelConfig = {
      name: config.llm.modelName,
      displayName: `${config.llm.modelProvider.toUpperCase()} - ${config.llm.modelName}`,
      provider: config.llm.modelProvider as 'openai' | 'anthropic',
      baseUrl: config.llm.baseUrl,
      apiKey: config.llm.apiKey || undefined,
      maxTokens: config.llm.maxTokens,
      temperature: config.llm.temperature,
      description: '主要配置模型',
      isEnabled: true
    };

    this.models.set(primaryModel.name, primaryModel);

    // 添加一些常见的备选模型配置
    const alternativeModels: ModelConfig[] = [
      // {
      //   name: 'gpt-4o-mini',
      //   displayName: 'OpenAI - GPT-4o Mini',
      //   provider: 'openai',
      //   baseUrl: 'https://api.openai.com/v1',
      //   apiKey: process.env.LLM_API_KEY,
      //   maxTokens: 8192,
      //   temperature: 0.7,
      //   description: '轻量级高性能模型',
      //   isEnabled: !!process.env.LLM_API_KEY
      // },
      // {
      //   name: 'gpt-4o',
      //   displayName: 'OpenAI - GPT-4o',
      //   provider: 'openai',
      //   baseUrl: 'https://api.openai.com/v1',
      //   apiKey: process.env.LLM_API_KEY,
      //   maxTokens: 16384,
      //   temperature: 0.7,
      //   description: '最新旗舰模型',
      //   isEnabled: !!process.env.LLM_API_KEY
      // },
      // {
      //   name: 'claude-3-haiku',
      //   displayName: 'Anthropic - Claude 3 Haiku',
      //   provider: 'anthropic',
      //   baseUrl: 'https://api.anthropic.com/v1',
      //   apiKey: process.env.LLM_API_KEY,
      //   maxTokens: 4096,
      //   temperature: 0.7,
      //   description: '快速且经济的模型',
      //   isEnabled: !!process.env.LLM_API_KEY
      // }
    ];

    // 添加备选模型
    alternativeModels.forEach(model => {
      if (!this.models.has(model.name)) {
        this.models.set(model.name, model);
      }
    });

    Logger.info(`${this.models.size} 個のフォールバックモデル設定を読み込みました`);
  }

  /**
   * すべての有効なモデルリストを取得
   */
  public getEnabledModels(): ModelConfig[] {
    const enabledModels = Array.from(this.models.values())
      .filter(model => model.isEnabled);

    // Apply ALLOW_MODELS filtering if configured
    const allowedModels = config.llm.allowedModels;
    if (allowedModels && allowedModels.length > 0) {
      return enabledModels
        .filter(model => allowedModels.includes(model.name))
        .sort((a, b) => a.displayName.localeCompare(b.displayName));
    }

    return enabledModels.sort((a, b) => a.displayName.localeCompare(b.displayName));
  }

  /**
   * すべてのモデルリストを取得（無効なものを含む）
   */
  public getAllModels(): ModelConfig[] {
    return Array.from(this.models.values())
      .sort((a, b) => a.displayName.localeCompare(b.displayName));
  }

  /**
   * 名前でモデル設定を取得
   */
  public getModel(name: string): ModelConfig | undefined {
    return this.models.get(name);
  }

  /**
   * モデルが存在し有効かどうかを確認
   */
  public isModelAvailable(name: string): boolean {
    const model = this.getModel(name);
    return !!model && model.isEnabled;
  }

  /**
   * モデルのヘルス状態を取得
   */
  public getHealthStatus(name: string): ModelHealthStatus | undefined {
    return this.healthStatus.get(name);
  }

  /**
   * すべてのモデルのヘルス状態を取得
   */
  public getAllHealthStatus(): ModelHealthStatus[] {
    return Array.from(this.healthStatus.values());
  }

  /**
   * モデルのヘルス状態を更新
   */
  public updateHealthStatus(name: string, status: Omit<ModelHealthStatus, 'name' | 'lastChecked'>): void {
    this.healthStatus.set(name, {
      name,
      ...status,
      lastChecked: new Date()
    });
  }

  /**
   * モデルのヘルスチェックを実行
   */
  public async checkModelHealth(modelName: string): Promise<ModelHealthStatus> {
    const model = this.getModel(modelName);
    if (!model) {
      return {
        name: modelName,
        isHealthy: false,
        error: 'Model not found',
        lastChecked: new Date()
      };
    }

    if (!model.isEnabled) {
      return {
        name: modelName,
        isHealthy: false,
        error: 'Model is disabled',
        lastChecked: new Date()
      };
    }

    const startTime = Date.now();

    try {
      // ここでは実際にモデル接続をテストする必要があります
      // 由于我们没有实际的模型连接测试逻辑，暂时返回模拟结果
      // 実際のアプリケーションでは、ここにモデルAPIへの簡単なpingリクエストを送信する必要があります

      const responseTime = Date.now() - startTime;

      const healthStatus: ModelHealthStatus = {
        name: modelName,
        isHealthy: true,
        responseTime,
        lastChecked: new Date()
      };

      this.updateHealthStatus(modelName, { isHealthy: true, responseTime });
      return healthStatus;

    } catch (error) {
      const healthStatus: ModelHealthStatus = {
        name: modelName,
        isHealthy: false,
        error: (error as Error).message,
        lastChecked: new Date()
      };

      this.updateHealthStatus(modelName, { 
        isHealthy: false, 
        error: (error as Error).message 
      });
      return healthStatus;
    }
  }

  /**
   * 批量检查所有启用模型的健康状态
   */
  public async checkAllModelsHealth(): Promise<ModelHealthStatus[]> {
    const enabledModels = this.getEnabledModels();
    const healthChecks = enabledModels.map(model => 
      this.checkModelHealth(model.name)
    );

    return Promise.all(healthChecks);
  }

  /**
   * 添加新的模型配置
   */
  public addModel(modelConfig: ModelConfig): void {
    this.models.set(modelConfig.name, modelConfig);
    Logger.info(`Added new model: ${modelConfig.name}`);
  }

  /**
   * 更新现有模型配置
   */
  public updateModel(name: string, updates: Partial<ModelConfig>): boolean {
    const existingModel = this.models.get(name);
    if (!existingModel) {
      return false;
    }

    const updatedModel = { ...existingModel, ...updates };
    this.models.set(name, updatedModel);
    Logger.info(`Updated model: ${name}`);
    return true;
  }

  /**
   * 删除模型配置
   */
  public removeModel(name: string): boolean {
    const result = this.models.delete(name);
    this.healthStatus.delete(name);
    if (result) {
      Logger.info(`Removed model: ${name}`);
    }
    return result;
  }

  /**
   * 启用模型
   */
  public enableModel(name: string): boolean {
    const model = this.getModel(name);
    if (model) {
      model.isEnabled = true;
      this.models.set(name, model);
      Logger.info(`Enabled model: ${name}`);
      return true;
    }
    return false;
  }

  /**
   * 禁用模型
   */
  public disableModel(name: string): boolean {
    const model = this.getModel(name);
    if (model) {
      model.isEnabled = false;
      this.models.set(name, model);
      Logger.info(`Disabled model: ${name}`);
      return true;
    }
    return false;
  }
}

