import { initChatModel } from "langchain";
import { HumanMessage, SystemMessage, AIMessage } from "@langchain/core/messages";
import { config } from '../config/environment.js';
import { Logger } from '../utils/logger.js';
import { ModelConfig } from '../models/modelManager.js';
import { MemorySaverManager } from '../memory/memorySaverManager.js';
import { PostgresMemoryManager } from '../memory/postgresMemoryManager.js';
import { createReactAgent } from "@langchain/langgraph/prebuilt";
import { BaseCheckpointSaver } from "@langchain/langgraph";
import { initializeMCPServers, getMCPTools } from '../mcp/mcpInitializer.js';

export class LegalAgent {
    private agent: any;
    private checkpointer!: BaseCheckpointSaver;
    private isInitialized: boolean = false;
    private modelConfig: ModelConfig;
    private sessionMemory: MemorySaverManager;
    private readonly maxContextMessages: number = 10; // 最大コンテキストメッセージ数

    private readonly systemPrompt = `
あなたは日本の法律に特化した役立つ弁護士アシスタントです。
すべての回答は真実でなければならず、回答を作成してはいけません。
質問に正確に答えるため、知識がない場合は、ツールを使用して関連する回答を検索してください。
必要に応じて、指定されたURLからウェブページを読み込んで情報を取得できます。
`;

    constructor(modelConfig?: ModelConfig) {
        // カスタムモデル設定が提供された場合はそれを使用し、そうでない場合はデフォルト設定を使用
        this.modelConfig = modelConfig || {
            name: config.llm.modelName,
            displayName: `${config.llm.modelProvider.toUpperCase()} - ${config.llm.modelName}`,
            provider: config.llm.modelProvider as 'ollama' | 'openai' | 'anthropic',
            baseUrl: config.llm.baseUrl,
            apiKey: config.llm.apiKey || undefined,
            maxTokens: config.llm.maxTokens,
            temperature: config.llm.temperature,
            description: 'Default model configuration',
            isEnabled: true
        };

        // セッションメモリの初期化
        this.sessionMemory = MemorySaverManager.getInstance();

        this.initializeAgent().catch(error => {
            Logger.error('Agent initialization failed', { error: error.message });
        });
    }

    /**
     * Agent を初期化
     */
    private async initializeAgent(): Promise<void> {
        try {
            Logger.info('Initializing LLM...', {
                model: this.modelConfig.name,
                provider: this.modelConfig.provider,
                // Mask baseUrl for security
                baseUrl: this.modelConfig.baseUrl ? '********' + this.modelConfig.baseUrl.slice(-4) : '未設定'
            });

            // プロバイダータイプに応じて適切な環境変数を設定
            if (this.modelConfig.provider === 'ollama') {
                process.env.OLLAMA_BASE_URL = this.modelConfig.baseUrl.replace('/v1', '');
                // Mask OLLAMA_BASE_URL for logging
                Logger.debug('Set OLLAMA_BASE_URL', { 
                    url: process.env.OLLAMA_BASE_URL ? '********' + process.env.OLLAMA_BASE_URL.slice(-4) : '未設定' 
                });
            }

            const llm = await initChatModel(
                this.modelConfig.name,
                {
                    modelProvider: this.modelConfig.provider as any,
                    temperature: this.modelConfig.temperature,
                    configuration: {
                        baseURL: this.modelConfig.baseUrl,
                        apiKey: this.modelConfig.apiKey,
                    },
                    maxTokens: this.modelConfig.maxTokens,
                }
            );

            Logger.info('LLM initialized successfully, connecting to MCP servers...');

            // Initialize MCP servers with resilient error handling
            // If some servers fail, we'll still use the ones that succeeded
            try {
                Logger.info('Starting MCP server initialization...');
                await initializeMCPServers();
                Logger.info('MCP servers initialization completed (some may have failed)');
            } catch (mcpError) {
                // This shouldn't happen anymore since we catch errors per-server,
                // but keep it as a safety net
                Logger.error('Unexpected error during MCP server initialization', {
                    error: (mcpError as Error).message,
                    stack: (mcpError as Error).stack
                });
            }

            // Get MCP tools as LangChain tools (will only include tools from successful servers)
            Logger.info('Retrieving MCP tools from available servers...');
            const mcpTools = await getMCPTools();

            if (mcpTools.length === 0) {
                Logger.warn('No MCP tools available. Agent will run without external tools.');
            } else {
                Logger.info('MCP tools loaded successfully', {
                    toolCount: mcpTools.length,
                    tools: mcpTools.map(t => t.name)
                });
            }

            // Create PostgresSaver for persistence
            Logger.debug('Initializing Postgres checkpointer...');
            const postgresMemory = PostgresMemoryManager.getInstance();
            this.checkpointer = await postgresMemory.getCheckpointer();

            // Create the agent using createReactAgent with MCP tools
            Logger.debug('Creating React Agent with MCP tools...');
            this.agent = createReactAgent({
                llm: llm,
                tools: mcpTools,
                checkpointSaver: this.checkpointer,
                messageModifier: this.systemPrompt
            });

            this.isInitialized = true;
            Logger.info(`Legal Agent initialized successfully with model: ${this.modelConfig.name}`);

        } catch (error) {
            Logger.error('Failed to initialize Legal Agent', {
                error: (error as Error).message,
                stack: (error as Error).stack
            });
            throw error;
        }
    }



    /**
     * 複雑なクエリの処理（セッションメモリ対応）
     */
    async processQuery(query: string, sessionId?: string): Promise<string> {
        if (!this.isInitialized) {
            await this.initializeAgent();
        }

        try {
            // デフォルトセッション ID を生成（未提供の場合）
            const effectiveSessionId = sessionId || this.generateDefaultSessionId();

            Logger.info('Processing legal query with session', {
                query: query.substring(0, 100) + '...',
                sessionId: effectiveSessionId
            });

            // Use the agent to stream - it will handle tool execution automatically
            const stream = await this.agent.stream(
                { messages: [new HumanMessage({ content: query })] },
                { 
                    configurable: { thread_id: effectiveSessionId },
                    streamMode: "messages"
                }
            );

            let fullResponse = '';
            let aiMessage: AIMessage | null = null;

            // Collect streaming output
            // When using streamMode: "messages", chunks are tuples [messageChunk, metadata]
            for await (const chunk of stream) {
                // Handle both array format [message, metadata] and direct message format
                const messageChunk = Array.isArray(chunk) ? chunk[0] : chunk;

                if (messageChunk && typeof messageChunk.content === 'string') {
                    const content = messageChunk.content;
                    fullResponse += content;
                    aiMessage = messageChunk as AIMessage;
                }
            }

            Logger.info('クエリが正常に処理されました', {
                responseLength: fullResponse.length,
                sessionId: effectiveSessionId
            });
            return fullResponse;

        } catch (error) {
            Logger.error('クエリ処理中にエラーが発生しました', { error: (error as Error).message, query });
            throw new Error(`クエリ処理に失敗しました：${(error as Error).message}`);
        }
    }

    /**
     * ストリーミングレスポンスの取得（リアルタイム表示用、セッションメモリ対応）
     */
    async getStream(query: string, sessionId?: string): Promise<AsyncIterable<any>> {
        if (!this.isInitialized) {
            await this.initializeAgent();
        }

        try {
            // デフォルトセッション ID を生成（未提供の場合）
            const effectiveSessionId = sessionId || this.generateDefaultSessionId();

            Logger.info('Processing legal query stream with session', {
                query: query.substring(0, 100) + '...',
                sessionId: effectiveSessionId
            });

            // Use the agent to stream - it will handle tool execution automatically
            const stream = await this.agent.stream(
                { messages: [new HumanMessage({ content: query })] },
                {
                    configurable: { thread_id: effectiveSessionId },
                    streamMode: "messages"
                }
            );

            // Create an async generator that yields message objects with type info
            async function* generateChunks() {
                for await (const chunk of stream) {
                    // When using streamMode: "messages", chunks are tuples [messageChunk, metadata]
                    // Extract the message chunk from the tuple
                    const messageChunk = Array.isArray(chunk) ? chunk[0] : chunk;

                    if (messageChunk) {
                        const messageType = messageChunk._getType ? messageChunk._getType() : 'ai';

                        // Check for tool calls in AIMessage
                        if (messageType === 'ai' && messageChunk.tool_calls && messageChunk.tool_calls.length > 0) {
                            for (const toolCall of messageChunk.tool_calls) {
                                yield {
                                    type: 'tool_start',
                                    tool: toolCall.name,
                                    args: toolCall.args,
                                    messageType: 'tool_call'
                                };
                            }
                        }

                        if (typeof messageChunk.content === 'string' && messageChunk.content.length > 0) {
                            const isToolMessage = messageType === 'tool' || messageType === 'ToolMessage';

                            yield {
                                type: isToolMessage ? 'tool' : 'llm',
                                content: messageChunk.content,
                                messageType: messageType,
                                toolName: isToolMessage ? messageChunk.name : undefined
                            };
                        }
                    }
                }
            }

            // Return the generator that yields message objects with type info
            return generateChunks();

        } catch (error) {
            Logger.error('Error processing stream query', { error: (error as Error).message, query });
            throw new Error(`ストリーム処理に失敗しました：${(error as Error).message}`);
        }
    }

    /**
     * エージェントが準備完了かどうかを確認
     */
    isReady(): boolean {
        return this.isInitialized;
    }

    /**
     * 現在使用中的モデル構成を取得
     */
    getModelConfig(): ModelConfig {
        return this.modelConfig;
    }

    /**
     * モデル名を取得
     */
    getModelName(): string {
        return this.modelConfig.name;
    }

    /**
     * 既定の会话 ID を生成
     */
    private generateDefaultSessionId(): string {
        return `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
    }

    /**
     * 会话統計情報を取得
     */
    getSessionStats() {
        return this.sessionMemory.getSessionStats();
    }

    /**
     * 会话をクリア
     */
    clearSession(sessionId: string): void {
        this.sessionMemory.clearSession(sessionId);
    }

    /**
     * 会话コンテキストを取得
     */
    getSessionContext(sessionId: string): Record<string, any> {
        return this.sessionMemory.getContext(sessionId);
    }

    /**
     * 会话コンテキストを更新
     */
    updateSessionContext(sessionId: string, context: Record<string, any>): void {
        this.sessionMemory.updateContext(sessionId, context);
    }
}

import { Client } from '@line/bot-sdk';
import { config } from '../config/environment.js';
import { LegalAgent } from '../agents/legalAgent.js';
import { Logger } from '../utils/logger.js';
import { 
  LineWebhookEvent, 
  LineMessage, 
  LineWebhookBody 
} from '../types/server';

export class LineBotHandler {
  private client: Client;
  private legalAgent: LegalAgent;

  constructor() {
    // 初始化 LINE Bot 客户端
    this.client = new Client({
      channelAccessToken: config.line.accessToken || '',
      channelSecret: config.line.channelSecret || ''
    });

    this.legalAgent = new LegalAgent();

    Logger.info('LINE Bot 处理器初始化完成', {
      hasChannelSecret: !!config.line.channelSecret,
      hasAccessToken: !!config.line.accessToken
    });
  }

  /**
   * 处理 LINE webhook 事件
   */
  async handleWebhook(body: LineWebhookBody): Promise<void> {
    if (!body.events || body.events.length === 0) {
      Logger.warn('收到空的 webhook 事件');
      return;
    }

    Logger.info('处理 LINE webhook 事件', { eventCount: body.events.length });

    // 并行处理所有事件
    const promises = body.events.map(event => this.handleEvent(event));
    await Promise.all(promises);
  }

  /**
   * 处理单个事件
   */
  private async handleEvent(event: LineWebhookEvent): Promise<void> {
    try {
      Logger.debug('处理事件', { 
        eventType: event.type,
        sourceType: event.source?.type,
        userId: event.source?.userId 
      });

      switch (event.type) {
        case 'message':
          await this.handleMessageEvent(event);
          break;
        case 'follow':
          await this.handleFollowEvent(event);
          break;
        case 'unfollow':
          await this.handleUnfollowEvent(event);
          break;
        case 'postback':
          await this.handlePostbackEvent(event);
          break;
        default:
          Logger.debug('未处理的事件类型', { eventType: event.type });
      }
    } catch (error) {
      Logger.error('处理事件时发生错误', { 
        error,
        eventType: event.type,
        userId: event.source?.userId
      });
    }
  }

  /**
   * 处理消息事件
   */
  private async handleMessageEvent(event: LineWebhookEvent): Promise<void> {
    if (!event.message || !event.replyToken) {
      Logger.warn('消息事件缺少必要字段');
      return;
    }

    const userId = event.source.userId;
    const message = event.message;

    Logger.info('处理用户消息', { 
      userId,
      messageType: message.type,
      messageText: message.text?.substring(0, 50) + '...'
    });

    try {
      let response: string;

      // 根据消息类型处理
      switch (message.type) {
        case 'text':
          response = await this.processLegalQuery(message.text || '', userId);
          break;
        default:
          response = '申し訳ありませんが、テキストメッセージのみ対応しています。';
      }

      // 发送回复
      await this.replyMessage(event.replyToken, response);

    } catch (error) {
      Logger.error('处理消息失败', { error, userId });
      await this.replyMessage(
        event.replyToken, 
        '申し訳ありませんが、現在サービスに問題が発生しています。しばらくしてから再度お試しください。'
      );
    }
  }

  private async handleFollowEvent(event: LineWebhookEvent): Promise<void> {
    const welcomeMessage = `法的アシスタントへようこそ！

法律に関するご質問をお気軽にどうぞ。契約、労働法、消費者保護など、さまざまな法的問題についてアドバイスいたします。

使い方：
・法律に関する質問をテキストで送信してください
・複雑な調査が必要な場合は少し時間がかかることがあります
・専門的な法的判断が必要な場合は弁護士への相談をお勧めします`;

    if (event.replyToken) {
      await this.replyMessage(event.replyToken, welcomeMessage);
    }
  }

  private async handleUnfollowEvent(event: LineWebhookEvent): Promise<void> {
    Logger.info('ユーザーのアンフォロー', { userId: event.source.userId });
  }

  private async handlePostbackEvent(event: LineWebhookEvent): Promise<void> {
    Logger.info('ポストバックイベントの処理', { 
      userId: event.source.userId,
      data: event.postback?.data 
    });

    // ここでは特定のポストバックデータを処理できます
    if (event.replyToken && event.postback?.data) {
      await this.replyMessage(event.replyToken, `選択されたオプション: ${event.postback.data}`);
    }
  }

  private async processLegalQuery(query: string, userId: string): Promise<string> {
    if (!query.trim()) {
      return '有効な質問を入力してください。';
    }

    Logger.info('法律クエリの処理', { 
      userId,
      query: query.substring(0, 100) + '...'
    });

    try {
      // セッション ID を生成（ユーザーごとに一意）
      const sessionId = `line_${userId}_${Date.now()}`;

      let response = '';

      // ストリーミングレスポンスを処理
      const stream = await this.legalAgent.getStream(query, sessionId);
      for await (const chunk of stream) {
        // getStream now yields string contents directly
        if (typeof chunk === 'string') {
          response += chunk;
        }
      }

      // レスポンスが長すぎないことを確認（LINE は 2000 文字に制限）
      if (response.length > 1900) {
        response = response.substring(0, 1900) + '\n\n（文字数制限のため、内容が省略されました）';
      }

      return response;
    } catch (error) {
      Logger.error('法律クエリの処理に失敗しました', { error, userId, query });
      return '申し訳ありませんが、質問の処理中にエラーが発生しました。もう一度お試しください。';
    }
  }

  private async replyMessage(replyToken: string, message: string): Promise<void> {
    try {
      await this.client.replyMessage(replyToken, {
        type: 'text',
        text: message
      });
      Logger.debug('メッセージの返信に成功しました');
    } catch (error) {
      Logger.error('メッセージの返信に失敗しました', { error, replyToken });
      throw error;
    }
  }

  /**
   * プッシュメッセージ（オプション機能）
   */
  async pushMessage(userId: string, message: string): Promise<void> {
    try {
      await this.client.pushMessage(userId, {
        type: 'text',
        text: message
      });
      Logger.debug('プッシュメッセージに成功しました', { userId });
    } catch (error) {
      Logger.error('プッシュメッセージに失敗しました', { error, userId });
      throw error;
    }
  }
}

import { LegalAgent } from './legalAgent.js';
import { ModelConfig } from '../models/modelManager.js';
import { Logger } from '../utils/logger.js';
import { config } from '../config/environment.js';

/**
 * エージェントマネージャー
 * セッションごとのエージェントインスタンスを管理
 */
export class AgentManager {
  private static instance: AgentManager;
  private agents: Map<string, LegalAgent>;

  private constructor() {
    this.agents = new Map();
    Logger.info('AgentManager initialized');
  }

  public static getInstance(): AgentManager {
    if (!AgentManager.instance) {
      AgentManager.instance = new AgentManager();
    }
    return AgentManager.instance;
  }

  /**
   * セッション ID に基づいてエージェントを取得または作成
   */
  public getOrCreateAgent(sessionId: string, modelConfig: ModelConfig): LegalAgent {
    const existingAgent = this.agents.get(sessionId);
    if (existingAgent) {
      Logger.debug('Using cached agent for session', { sessionId });
      return existingAgent;
    }

    Logger.info('Creating new agent for session', { sessionId, model: modelConfig.name });
    const agent = new LegalAgent(modelConfig);
    this.agents.set(sessionId, agent);
    return agent;
  }

  /**
   * エージェントを取得（互換性のため）
   */
  public async getAgent(sessionId?: string): Promise<LegalAgent> {
    // セッション ID が指定されていない場合はデフォルトエージェントを返す
    const actualSessionId = sessionId || 'default';

    Logger.info('エージェント取得開始', {
      sessionId: actualSessionId,
      config_llm_modelName: config.llm.modelName,
      config_llm_provider: config.llm.modelProvider,
      config_llm_baseUrl: config.llm.baseUrl,
      config_llm_apiKey: config.llm.apiKey ? '***' + config.llm.apiKey.slice(-4) : '未設定'
    });

    const defaultModelConfig: ModelConfig = {
      name: config.llm.modelName,
      displayName: `${config.llm.modelProvider.toUpperCase()} - ${config.llm.modelName}`,
      provider: config.llm.modelProvider as 'openai' | 'anthropic',
      baseUrl: config.llm.baseUrl,
      apiKey: config.llm.apiKey,
      maxTokens: config.llm.maxTokens,
      temperature: config.llm.temperature,
      description: 'Default model',
      isEnabled: true
    };

    Logger.info('エージェント作成', {
      sessionId: actualSessionId,
      modelConfig_name: defaultModelConfig.name,
      modelConfig_provider: defaultModelConfig.provider,
      modelConfig_baseUrl: defaultModelConfig.baseUrl,
      modelConfig_apiKey: defaultModelConfig.apiKey ? '***' + defaultModelConfig.apiKey.slice(-4) : '未設定'
    });

    return this.getOrCreateAgent(actualSessionId, defaultModelConfig);
  }

  /**
   * セッションのエージェントをクリア
   */
  public clearAgent(sessionId: string): void {
    this.agents.delete(sessionId);
    Logger.info('Agent cleared for session', { sessionId });
  }

  /**
   * すべてのエージェントキャッシュをクリア
   */
  public clearAllAgents(): void {
    this.agents.clear();
    Logger.info('All agents cleared');
  }

  /**
   * アクティブなセッション数を取得
   */
  public getActiveSessionCount(): number {
    return this.agents.size;
  }
}

